{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial search, noise handling, and cost minimization. I am breaking it into geometric modeling, probabilistic query optimization, and cost-benefit analysis.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Represent the known polyomino shapes as sets of relative coordinates. For a given set of shapes, define the possible valid placements on a grid such that no two polyominoes overlap and all shapes are contained within the grid boundaries. Provide a method to calculate the intersection of a proposed drilling coordinate with all possible valid placements."
    },
    {
      "label": "probabilistic_query_optimizer",
      "instructions": "Given a set of possible polyomino placements and a noisy aggregate query model (where a query returns a signal with a known error distribution), develop a Bayesian update rule. This rule should calculate the posterior probability of each placement being correct after receiving a noisy signal from a specific set of coordinates."
    },
    {
      "label": "cost_minimization_strategist",
      "instructions": "Develop an objective function to decide between three actions: 1. Drilling (high cost, high certainty), 2. Noisy Aggregate Query (low cost, low certainty), and 3. Final Guess (zero cost, high risk). The function should maximize the expected information gain per unit of cost, specifically targeting the reduction of entropy in the placement probability distribution."
    }
  ],
  "synthesis_brief": "Combine the geometric constraints from the geometric_modeler with the Bayesian update logic from the probabilistic_query_optimizer to maintain a real-time probability map of oil locations. Use the cost_minimization_strategist's objective function to select the next optimal action (drill vs query) until the entropy of the placement distribution falls below a threshold that justifies a final guess."
}

